// looksLikeDoctorInterstitial reports whether the response body matches a known
// bot-detection challenge page (Cloudflare, Akamai, Vercel, AWS WAF, DataDome,
// PerimeterX). Only fires on the doctor probe — used to distinguish "transport
// reached the wall" from "transport failed entirely." Returns the vendor name
// when matched, or empty string when no match.
//
// Markers are anchored to <title> or vendor-specific strings to avoid
// false-positives on benign content. For example, a recipe titled "Just A
// Moment of Pause Cookies" must NOT match the Cloudflare challenge marker;
// only "<title>just a moment" (the actual interstitial title) does.
func looksLikeDoctorInterstitial(body []byte) string {
	if len(body) == 0 {
		return ""
	}
	limit := len(body)
	if limit > 8192 {
		limit = 8192
	}
	prefix := strings.ToLower(string(body[:limit]))
	if !strings.Contains(prefix, "<title") {
		// Every bot interstitial we recognize sets a <title>; bodies without
		// one are body-only API responses, not challenge pages.
		return ""
	}
	switch {
	case strings.Contains(prefix, "<title>just a moment") || // CF JS challenge
		strings.Contains(prefix, "challenges.cloudflare.com") || // CF Turnstile
		(strings.Contains(prefix, "attention required") && strings.Contains(prefix, "cloudflare")):
		return "Cloudflare"
	case strings.Contains(prefix, "akamai") && (strings.Contains(prefix, "request unsuccessful") || strings.Contains(prefix, "access denied")):
		return "Akamai"
	case strings.Contains(prefix, "x-vercel-mitigated") || strings.Contains(prefix, "x-vercel-challenge-token") ||
		(strings.Contains(prefix, "vercel") && strings.Contains(prefix, "challenge")):
		return "Vercel"
	case strings.Contains(prefix, "request blocked") && strings.Contains(prefix, "aws waf"):
		return "AWS WAF"
	case strings.Contains(prefix, "datadome") && (strings.Contains(prefix, "blocked") || strings.Contains(prefix, "captcha") || strings.Contains(prefix, "challenge")):
		return "DataDome"
	case strings.Contains(prefix, "perimeterx") || strings.Contains(prefix, "px-captcha"):
		return "PerimeterX"
	}
	return ""
}

func authLane(status, source, hint string) map[string]any {
	lane := map[string]any{"status": status}
	if source != "" {
		lane["source"] = source
	}
	if hint != "" {
		lane["hint"] = hint
	}
	return lane
}

func probeAuthLane(ctx context.Context, c *client.Client, header, source, path, missingHint string) map[string]any {
	if header == "" {
		return authLane("missing", source, missingHint)
	}
	headers := map[string]string{
		"Authorization": header,
		"User-Agent":    "x-twitter-pp-cli",
	}
	body, err := c.GetWithHeaders(ctx, path, nil, headers)
	if err == nil {
		lane := authLane("ok", source, "")
		if path == "/2/users/me" {
			if user := userSummaryFromMeProbe(body); len(user) > 0 {
				lane["probe"] = "/2/users/me ok"
				lane["user"] = user
			}
		}
		return lane
	}
	var apiErr *client.APIError
	if errors.As(err, &apiErr) {
		body := apiErr.Body
		switch {
		case apiErr.StatusCode == 401:
			lane := authLane("invalid", source, "token was rejected; refresh or replace this credential")
			lane["http_status"] = apiErr.StatusCode
			return lane
		case apiErr.StatusCode == 403 && xAppOnlyUnsupportedAuth(body):
			lane := authLane("invalid", source, "this credential appears to be app-only; set/import a real OAuth2 user-context token in X_OAUTH2_USER_TOKEN")
			lane["http_status"] = apiErr.StatusCode
			lane["classification"] = "app_only_token_used_for_user_context"
			return lane
		case apiErr.StatusCode == 403:
			lane := authLane("invalid", source, "credential reached X but lacks permission for this probe")
			lane["http_status"] = apiErr.StatusCode
			return lane
		default:
			lane := authLane("unknown", source, "probe reached X but returned a non-auth HTTP status")
			lane["http_status"] = apiErr.StatusCode
			return lane
		}
	}
	lane := authLane("unknown", source, "probe could not complete")
	lane["error"] = err.Error()
	return lane
}

func cookieAuthLane() map[string]any {
	cookies, err := client.LoadCookieAuth()
	if err != nil {
		return authLane("missing", "cookies.json", "capture X Articles cookies with `x-twitter-pp-cli auth login --chrome`; this does not configure v2 API OAuth2 user-context auth")
	}
	lane := authLane("ok", "cookies.json", "")
	if cookies.ArticleUserID() != "" {
		lane["user_id_present"] = true
	}
	return lane
}

const xAppOnlyProbePath = "/2/users/2244994945"

func buildAuthLaneReport(ctx context.Context, cfg *config.Config, c *client.Client) map[string]any {
	userSource := cfg.UserContextAuthSource()
	if userSource == "" {
		userSource = "X_OAUTH2_USER_TOKEN/access_token"
	}

	type laneResult struct {
		key  string
		lane map[string]any
	}
	results := make(chan laneResult, 2)
	go func() {
		results <- laneResult{
			key: "app_only_api",
			lane: probeAuthLane(
				ctx,
				c,
				cfg.AppOnlyAuthHeader(),
				"X_BEARER_TOKEN",
				xAppOnlyProbePath,
				"set X_BEARER_TOKEN for app-only public API reads",
			),
		}
	}()
	go func() {
		results <- laneResult{
			key: "oauth2_user_context",
			lane: probeAuthLane(
				ctx,
				c,
				cfg.UserContextAuthHeader(),
				userSource,
				"/2/users/me",
				"set X_OAUTH2_USER_TOKEN to a real OAuth2 user-context token for /2/users/me, personal reads, writes, bookmarks, and user-context analytics",
			),
		}
	}()

	lanes := map[string]any{"x_articles_cookie": cookieAuthLane()}
	for range 2 {
		result := <-results
		lanes[result.key] = result.lane
	}
	attachUserContextTokenMetadata(lanes, cfg)
	return lanes
}

func userSummaryFromMeProbe(body []byte) map[string]any {
	var envelope struct {
		Data struct {
			ID       string `json:"id"`
			Username string `json:"username"`
			Name     string `json:"name"`
		} `json:"data"`
	}
	if err := json.Unmarshal(body, &envelope); err != nil {
		return nil
	}
	user := map[string]any{}
	if envelope.Data.ID != "" {
		user["id"] = envelope.Data.ID
	}
	if envelope.Data.Username != "" {
		user["username"] = envelope.Data.Username
		user["handle"] = "@" + strings.TrimPrefix(envelope.Data.Username, "@")
	}
	if envelope.Data.Name != "" {
		user["name"] = envelope.Data.Name
	}
	return user
}

func attachUserContextTokenMetadata(lanes map[string]any, cfg *config.Config) {
	if cfg == nil {
		return
	}
	lane, _ := lanes["oauth2_user_context"].(map[string]any)
	if lane == nil {
		return
	}
	if !cfg.TokenExpiry.IsZero() {
		lane["expires_at"] = cfg.TokenExpiry.UTC().Format(time.RFC3339)
	}
	if cfg.RefreshToken != "" {
		lane["refresh_token_present"] = true
	} else if cfg.AccessToken != "" || cfg.XOauth2UserToken != "" || cfg.AuthHeaderVal != "" {
		lane["refresh_token_present"] = false
	}
	if len(cfg.Scopes) > 0 {
		lane["scopes"] = cfg.Scopes
		if missing := missingScopesForWorkflows(cfg.Scopes); len(missing) > 0 {
			lane["missing_for"] = missing
		}
	} else if cfg.AccessToken != "" || cfg.XOauth2UserToken != "" || cfg.AuthHeaderVal != "" {
		lane["scopes_known"] = false
		hint, _ := lane["hint"].(string)
		if strings.TrimSpace(hint) == "" {
			lane["hint"] = "scope metadata is not stored; import OAuth2 with --scopes so agents can preflight workflows"
		}
	}
}

func missingScopesForWorkflows(scopes []string) map[string][]string {
	have := map[string]bool{}
	for _, scope := range scopes {
		scope = strings.TrimSpace(scope)
		if scope != "" {
			have[scope] = true
		}
	}
	required := map[string][]string{
		"identity":        {"users.read", "tweet.read"},
		"personal_reads":  {"users.read", "tweet.read"},
		"bookmarks":       {"bookmark.read", "tweet.read", "users.read"},
		"likes":           {"like.read", "tweet.read", "users.read"},
		"follows":         {"follows.read", "users.read"},
		"public_writes":   {"tweet.write", "tweet.read", "users.read"},
		"dm":              {"dm.read", "dm.write", "users.read"},
		"offline_refresh": {"offline.access"},
	}
	missing := map[string][]string{}
	for workflow, needed := range required {
		var absent []string
		for _, scope := range needed {
			if !have[scope] {
				absent = append(absent, scope)
			}
		}
		if len(absent) > 0 {
			missing[workflow] = absent
		}
	}
	return missing
}

func laneStatus(lanes map[string]any, key string) string {
	lane, _ := lanes[key].(map[string]any)
	status, _ := lane["status"].(string)
	if status == "" {
		return "unknown"
	}
	return status
}

func credentialSummary(lanes map[string]any) string {
	human := func(status string) string {
		switch status {
		case "missing":
			return "not set"
		default:
			return status
		}
	}
	return fmt.Sprintf("app-only API %s; OAuth2 user-context %s; X Articles cookie %s",
		human(laneStatus(lanes, "app_only_api")),
		human(laneStatus(lanes, "oauth2_user_context")),
		human(laneStatus(lanes, "x_articles_cookie")),
	)
}

func newDoctorCmd(flags *rootFlags) *cobra.Command {
	var failOn string
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Check CLI health",
		Example: `  x-twitter-pp-cli doctor
  x-twitter-pp-cli doctor --json
  x-twitter-pp-cli doctor --fail-on warn`,
		RunE: func(cmd *cobra.Command, args []string) error {
			report := map[string]any{}
			selectedProfile := flags.profileName
			if selectedProfile == "" {
				selectedProfile = "default"
			}
			report["selected_profile"] = selectedProfile

			// Check config
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				report["config"] = fmt.Sprintf("error: %s", err)
			} else {
				report["config"] = "ok"
				report["config_path"] = cfg.Path
				report["base_url"] = cfg.BaseURL
				// agentcookie integration is soft: if the agentcookie daemon manages
				// this CLI's config, it writes a marker file alongside the config and
				// AuthSource is upgraded to "agentcookie" in config.Load. Surface the
				// state explicitly so users can tell whether the bus is wired up.
				if cfg.AuthSource == "agentcookie" {
					report["agentcookie"] = "detected (managing credentials)"
				} else {
					report["agentcookie"] = "not detected (optional)"
				}
			}

			// Check auth
			authConfigured := false
			if cfg != nil {
				header := cfg.AuthHeader()
				if header == "" {
					report["auth"] = "not configured"
					report["auth_hint"] = "export X_BEARER_TOKEN=<your-key>"
					report["auth_key_url"] = "https://console.x.com/"
					report["auth_instructions"] = "Bearer Token (required) is on your app Keys and Tokens page at console.x.com. Optional X_OAUTH2_USER_TOKEN unlocks v2 writes and personal reads. X Articles authoring uses browser cookies captured via auth login --chrome."
				} else {
					authConfigured = true
					report["auth"] = "configured"
					report["auth_source"] = cfg.AuthSource
				}
			}

			// Check auth environment variables
			authEnvSet := []string{}
			authEnvRequiredMissing := []string{}
			authEnvInfo := []string{}
			authEnvOptionalNames := []string{}
			// Validation rejects multi-OR-group specs upstream, so the single optional-satisfied state is sufficient at runtime.
			authEnvOptionalSatisfied := false
			if os.Getenv("X_BEARER_TOKEN") != "" {
				authEnvSet = append(authEnvSet, "X_BEARER_TOKEN")
			} else if authConfigured {
				authSource, _ := report["auth_source"].(string)
				if authSource == "" {
					authSource = "config"
				}
				authEnvInfo = append(authEnvInfo, "credentials available from "+authSource)
			} else {
				authEnvRequiredMissing = append(authEnvRequiredMissing, "X_BEARER_TOKEN")
			}
			if strings.Contains("Optional OAuth2 user-context token. Unlocks v2 writes (post, like, repost, bookmark, follow, DM) and personal reads (me, mentions, home timeline, bookmarks). Sent as Authorization Bearer; obtain from an OAuth2 authorization-code + PKCE flow and set/import explicitly. auth login --chrome is cookie-only for X Articles.", " OR ") {
				authEnvOptionalNames = append(authEnvOptionalNames, "X_OAUTH2_USER_TOKEN")
				if os.Getenv("X_OAUTH2_USER_TOKEN") != "" {
					authEnvSet = append(authEnvSet, "X_OAUTH2_USER_TOKEN")
					authEnvOptionalSatisfied = true
				}
			} else if os.Getenv("X_OAUTH2_USER_TOKEN") != "" {
				authEnvSet = append(authEnvSet, "X_OAUTH2_USER_TOKEN")
			} else {
				authEnvInfo = append(authEnvInfo, "X_OAUTH2_USER_TOKEN optional")
			}
			switch {
			case len(authEnvRequiredMissing) > 0:
				report["env_vars"] = "ERROR missing required: " + strings.Join(authEnvRequiredMissing, ", ")
			case len(authEnvOptionalNames) > 1 && !authEnvOptionalSatisfied:
				report["env_vars"] = "INFO set one of: " + strings.Join(authEnvOptionalNames, " or ")
			case len(authEnvInfo) > 0 && authConfigured:
				report["env_vars"] = "OK " + strings.Join(authEnvInfo, "; ")
			case len(authEnvInfo) > 0:
				report["env_vars"] = "INFO " + strings.Join(authEnvInfo, "; ")
			default:
				report["env_vars"] = fmt.Sprintf("OK %d/%d available", len(authEnvSet), 2)
			}

			// Check API connectivity and validate credentials.
			//
			// The doctor uses the same client every other command uses --
			// flags.newClient() returns a *client.Client wrapping whatever
			// transport the spec declared (Surf for browser-chrome, stdlib
			// for standard). A separate stdlib http.Client would silently
			// bypass that choice and report false negatives against
			// Cloudflare-fronted, Akamai-fronted, or otherwise bot-detected
			// sites. By going through flags.newClient(), the doctor's
			// reachability verdict matches what real commands experience.
			if cfg != nil && cfg.BaseURL != "" {
				c, clientErr := flags.newClient()
				if clientErr != nil {
					report["api"] = fmt.Sprintf("client init error: %s", clientErr)
				} else {
					c.NoCache = true
					// Step 1: Basic reachability via the configured transport.
					healthPath := "/2/users/me"
					if !strings.HasPrefix(healthPath, "/") {
						healthPath = "/" + healthPath
					}
					reachBody, reachErr := c.Get(cmd.Context(), healthPath, nil)
					var reachAPIErr *client.APIError
					switch {
					case reachErr == nil:
						// 2xx response — clearly reachable. Still inspect the
						// body for a known interstitial; some bot walls return
						// 200 with a JS challenge page.
						if vendor := looksLikeDoctorInterstitial(reachBody); vendor != "" {
							report["api"] = fmt.Sprintf("blocked by %s interstitial — the configured transport reached the wall. Try a different network, wait for the IP-level rate limit to clear, or check that the browser-chrome transport is bound correctly.", vendor)
						} else {
							report["api"] = "reachable"
						}
					case errors.As(reachErr, &reachAPIErr):
						// Non-2xx from the server. The network reached, the
						// server responded — that's "reachable" for our
						// purposes. Inspect the response body for a known
						// interstitial first; otherwise note the status.
						status := reachAPIErr.StatusCode
						if vendor := looksLikeDoctorInterstitial([]byte(reachAPIErr.Body)); vendor != "" {
							report["api"] = fmt.Sprintf("blocked by %s interstitial (HTTP %d) — the configured transport reached the wall.", vendor, status)
						} else {
							report["api"] = fmt.Sprintf("reachable (HTTP %d at /)", status)
						}
					default:
						// Network-level failure: DNS, connection refused, TLS,
						// transport init, etc. The transport itself didn't
						// connect.
						report["api"] = fmt.Sprintf("unreachable: %s", reachErr)
					}

					// Step 2: Validate each X auth lane separately. X's v2 API
					// distinguishes app-only bearer auth from OAuth2 user-context
					// auth, and X Articles uses browser cookies. A single
					// "credentials valid" verdict is misleading here.
					if reachErr != nil && !errors.As(reachErr, &reachAPIErr) {
						report["credentials"] = "skipped (API unreachable)"
					} else {
						authLanes := buildAuthLaneReport(cmd.Context(), cfg, c)
						report["auth_lanes"] = authLanes
						report["credentials"] = credentialSummary(authLanes)
					}
				}
			} else if cfg != nil && cfg.BaseURL == "" {
				report["api"] = "not configured (set base_url in config file)"
			}
			// Cache health: only reported when this CLI has a local store.
			// Surfaces rows + last_synced_at per resource, schema version,
			// and a fresh/stale/unknown verdict so agents can introspect
			// whether to trust the cached data before issuing queries.
			report["cache"] = collectCacheReport(cmd.Context(), "")

			// Verify mode state. Surfaced so an operator who unintentionally
			// inherits PRINTING_PRESS_VERIFY=1 (parent shell, CI runner, container
			// image) detects the foot-gun without inspecting a response body.
			// Pairs with the synthetic envelope's verify_noop / reason literals
			// as a second diagnosis anchor.
			if cliutil.IsVerifyEnv() {
				if cliutil.IsVerifyLiveHTTPEnv() {
					report["verify_mode"] = "INFO ACTIVE — live HTTP opt-in (mutating verbs dial out)"
				} else {
					report["verify_mode"] = "INFO ACTIVE — mutating HTTP verbs short-circuit (PRINTING_PRESS_VERIFY=1; no network calls for DELETE/POST/PUT/PATCH)"
				}
			} else {
				report["verify_mode"] = "normal operation"
			}

			report["version"] = version

			if flags.asJSON {
				if err := printJSONFiltered(cmd.OutOrStdout(), report, flags); err != nil {
					return err
				}
				return doctorExitForFailOn(failOn, report)
			}

			// Human-readable output with color
			w := cmd.OutOrStdout()
			checkKeys := []struct{ key, label string }{
				{"config", "Config"},
				{"auth", "Auth"},
				{"env_vars", "Env Vars"},
				{"verify_mode", "Verify Mode"},
				{"api", "API"},
				{"credentials", "Credentials"},
			}
			for _, ck := range checkKeys {
				v, ok := report[ck.key]
				if !ok {
					continue
				}
				s := fmt.Sprintf("%v", v)
				indicator := green("OK")
				switch {
				case strings.HasPrefix(s, "INFO"):
					indicator = yellow("INFO")
				case strings.HasPrefix(s, "ERROR"):
					indicator = red("FAIL")
				case strings.HasPrefix(s, "optional"):
					// Optional-auth CLI with no key set — informational, not a failure.
					indicator = yellow("INFO")
				case strings.Contains(s, "scope-limited"):
					indicator = yellow("WARN")
				case strings.Contains(s, "not verified"):
					// "present, not verified" — credentials are loaded but no
					// probe ran. Informational, not a warning; a clean config
					// shouldn't render yellow WARN in CI dashboards.
					indicator = yellow("INFO")
				case strings.Contains(s, "error") || strings.Contains(s, "not configured") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") || strings.Contains(s, "missing"):
					indicator = red("FAIL")
				case s == "not required":
					// Public APIs: no auth needed is a healthy state, not a warning.
					indicator = green("OK")
				case strings.Contains(s, "not ") || strings.Contains(s, "skipped") || strings.Contains(s, "inferred"):
					indicator = yellow("WARN")
				}
				fmt.Fprintf(w, "  %s %s: %s\n", indicator, ck.label, s)
			}
			if lanesAny, ok := report["auth_lanes"]; ok {
				if lanes, ok := lanesAny.(map[string]any); ok {
					renderAuthLaneReport(w, lanes)
				}
			}
			// Print info keys without status indicator
			for _, key := range []string{"config_path", "base_url", "auth_source", "version"} {
				if v, ok := report[key]; ok {
					fmt.Fprintf(w, "  %s: %v\n", key, v)
				}
			}
			// Print auth setup hints (indented under Auth line)
			if hint, ok := report["auth_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			if keyURL, ok := report["auth_key_url"]; ok {
				fmt.Fprintf(w, "  Get a key at: %v\n", keyURL)
			}
			if instructions, ok := report["auth_instructions"]; ok {
				fmt.Fprintf(w, "  %v\n", instructions)
			}
			// Cache section: render after the primary health block so it
			// sits next to version info, mirroring the JSON report layout.
			if cacheAny, ok := report["cache"]; ok {
				if cacheRep, ok := cacheAny.(map[string]any); ok {
					renderCacheReport(w, cacheRep)
				}
			}
			return doctorExitForFailOn(failOn, report)
		},
	}
	cmd.Flags().StringVar(&failOn, "fail-on", "", "Exit non-zero when a health level is reached: stale, error. Default is never.")
	return cmd
}

// doctorExitForFailOn returns a non-nil error when the report's worst
// status meets or exceeds the --fail-on threshold. "error" always trips
// when any section reports an error; "stale" also trips when the cache
// section is stale. The default empty string means never fail on status.
func doctorExitForFailOn(failOn string, report map[string]any) error {
	if failOn == "" {
		return nil
	}
	worstError := false
	worstStale := false
	for _, v := range report {
		s, ok := v.(string)
		if ok {
			if strings.Contains(s, "error") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") || strings.Contains(s, "missing") {
				worstError = true
			}
		}
		if m, ok := v.(map[string]any); ok {
			if st, _ := m["status"].(string); st == "error" {
				worstError = true
			} else if st == "stale" {
				worstStale = true
			}
		}
	}
	switch failOn {
	case "error":
		if worstError {
			return fmt.Errorf("doctor: --fail-on=error triggered")
		}
	case "stale":
		if worstError || worstStale {
			return fmt.Errorf("doctor: --fail-on=stale triggered")
		}
	default:
		return fmt.Errorf("doctor: unknown --fail-on value %q (valid: stale, error)", failOn)
	}
	return nil
}

// collectCacheReport opens the local store, reads per-resource sync state,
// and returns a map summarising cache health. Never panics on missing DB
// or open failure; returns a map with status=unknown or status=error so the
// caller can render and agents can interpret.
//
// staleAfterSpec is the CLI's configured threshold (e.g. "6h"); empty means
// use the runtime default. The default is deliberately conservative (6h)
// because the alternative is no freshness story at all.
func collectCacheReport(ctx context.Context, staleAfterSpec string) map[string]any {
	report := map[string]any{}
	dbPath := defaultDBPath("x-twitter-pp-cli")
	report["db_path"] = dbPath

	fi, err := os.Stat(dbPath)
	if err != nil {
		if os.IsNotExist(err) {
			report["status"] = "unknown"
			report["hint"] = "Database not created yet; run 'x-twitter-pp-cli sync' to hydrate."
			return report
		}
		report["status"] = "error"
		report["error"] = err.Error()
		return report
	}
	report["db_bytes"] = fi.Size()

	s, err := store.OpenWithContext(ctx, dbPath)
	if err != nil {
		report["status"] = "error"
		report["error"] = err.Error()
		return report
	}
	defer s.Close()

	if v, verr := s.SchemaVersion(); verr == nil {
		report["schema_version"] = v
	}

	staleAfter := 6 * time.Hour
	if staleAfterSpec != "" {
		if d, derr := time.ParseDuration(staleAfterSpec); derr == nil {
			staleAfter = d
		}
	}

	rows, qerr := s.DB().Query(`SELECT resource_type, COALESCE(total_count, 0), last_synced_at FROM sync_state ORDER BY resource_type`)
	if qerr != nil {
		// sync_state may not exist on a fresh DB that has migrated but not
		// yet had any sync runs — treat as unknown rather than error.
		report["status"] = "unknown"
		report["hint"] = "No sync state recorded; run 'x-twitter-pp-cli sync' to populate."
		return report
	}
	defer rows.Close()

	var resources []map[string]any
	fresh := true
	haveAny := false
	oldest := time.Duration(0)
	for rows.Next() {
		var rtype string
		var count int64
		var lastSynced sql.NullTime
		if err := rows.Scan(&rtype, &count, &lastSynced); err != nil {
			continue
		}
		r := map[string]any{"type": rtype, "rows": count}
		if lastSynced.Valid {
			haveAny = true
			r["last_synced_at"] = lastSynced.Time.UTC().Format(time.RFC3339)
			age := time.Since(lastSynced.Time)
			r["staleness"] = age.Round(time.Minute).String()
			if age > staleAfter {
				fresh = false
			}
			if age > oldest {
				oldest = age
			}
		} else {
			r["staleness"] = "never"
			fresh = false
		}
		resources = append(resources, r)
	}
	report["resources"] = resources
	report["stale_after"] = staleAfter.String()

	switch {
	case !haveAny && len(resources) == 0:
		report["status"] = "unknown"
		report["hint"] = "sync_state is empty; run 'x-twitter-pp-cli sync' to hydrate."
	case fresh:
		report["status"] = "fresh"
	default:
		report["status"] = "stale"
		report["oldest_age"] = oldest.Round(time.Minute).String()
		report["hint"] = "Some resources are older than stale_after; run 'x-twitter-pp-cli sync' to refresh."
	}
	return report
}

func renderCacheReport(w io.Writer, rep map[string]any) {
	status, _ := rep["status"].(string)
	indicator := green("OK")
	switch status {
	case "stale":
		indicator = yellow("WARN")
	case "error":
		indicator = red("FAIL")
	case "unknown":
		indicator = yellow("INFO")
	}
	fmt.Fprintf(w, "  %s Cache: %s\n", indicator, status)
	if v, ok := rep["db_path"]; ok {
		fmt.Fprintf(w, "    db_path: %v\n", v)
	}
	if v, ok := rep["schema_version"]; ok {
		fmt.Fprintf(w, "    schema_version: %v\n", v)
	}
	if v, ok := rep["db_bytes"]; ok {
		fmt.Fprintf(w, "    db_bytes: %v\n", v)
	}
	if v, ok := rep["stale_after"]; ok {
		fmt.Fprintf(w, "    stale_after: %v\n", v)
	}
	if v, ok := rep["oldest_age"]; ok {
		fmt.Fprintf(w, "    oldest_age: %v\n", v)
	}
	if resourcesAny, ok := rep["resources"]; ok {
		if resources, ok := resourcesAny.([]map[string]any); ok && len(resources) > 0 {
			fmt.Fprintf(w, "    resources:\n")
			for _, r := range resources {
				rtype, _ := r["type"].(string)
				rows := r["rows"]
				staleness, _ := r["staleness"].(string)
				fmt.Fprintf(w, "      - %s: %v rows, %s\n", rtype, rows, staleness)
			}
		}
	}
	if hint, ok := rep["hint"]; ok {
		fmt.Fprintf(w, "    hint: %v\n", hint)
	}
}

func renderAuthLaneReport(w io.Writer, lanes map[string]any) {
	fmt.Fprintf(w, "  Auth Lanes:\n")
	for _, entry := range []struct {
		key   string
		label string
	}{
		{"app_only_api", "app-only API auth"},
		{"oauth2_user_context", "OAuth2 user-context auth"},
		{"x_articles_cookie", "X Articles cookie auth"},
	} {
		lane, _ := lanes[entry.key].(map[string]any)
		status, _ := lane["status"].(string)
		if status == "" {
			status = "unknown"
		}
		indicator := green("OK")
		switch status {
		case "missing", "unknown":
			indicator = yellow("INFO")
		case "invalid":
			indicator = red("FAIL")
		}
		fmt.Fprintf(w, "    %s %s: %s\n", indicator, entry.label, status)
		if source, _ := lane["source"].(string); source != "" {
			fmt.Fprintf(w, "      source: %s\n", source)
		}
		if hint, _ := lane["hint"].(string); hint != "" {
			fmt.Fprintf(w, "      hint: %s\n", hint)
		}
	}
}
